var e=[{id:`L2_1`,type:`dialog`,speaker:`CHOI_ALPHA_NULL_SHORT`,text:{KOREA:`훗, 이걸로 악의 무리를 전부 제거한 건가?`,JPN:`ふっ、これで悪の群れはすべて排除したか？`,ENG:`Heh. Did we defeat the entire forces of evil?`,TWN:`哼，邪惡之徒都處理完了吧？`},stage:{bg:`CITY_STREET_DISASTER`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CHOI_ALPHA_NULL_SHORT`,face:`UNIT_PRIDE`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`CHOWON_PERSONA_NULL_NULL`,text:{KOREA:`그렇다고 하기엔 차원 계면이 불안정하고 CSE 레벨도 여전히 높네요.`,JPN:`その割には次元界面が不安定で、CSEのレベルも相変わらず高いです。`,ENG:`The dimension surface is unstable and the CSE level is still high. So it doesn't seem like it.`,TWN:`但是次元介面還是不穩定，CSE等級也仍然很高。`},stage:{bg:`CITY_STREET_DISASTER`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CHOWON_PERSONA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`CHOWON_PERSONA_NULL_NULL`,text:{KOREA:`이 날씨에 눈이 내리는 걸 보니, 애초에 침식체들의 등장과는 상관없었던 걸지도 모르겠어요.`,JPN:`この天気に雪が降ってるのを見ると、そもそも侵食体たちの登場とは関係なかったのかもしれません。`,ENG:`But seeing how it's snowing in this weather, maybe the C.O.s' appearance was never relevant.`,TWN:`在這種天氣下雪，或許和侵蝕體的出現根本就沒有關聯。`},stage:{bg:`CITY_STREET_DISASTER`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CHOWON_PERSONA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`SPEAR_ALPHA_NULL_SHORT`,text:{KOREA:`그럼 아직도 침식파가 남아있다는 거야? 어째서?`,JPN:`じゃあ、まだ侵食波が残ってるってこと？　なんで？`,ENG:`Then there's still Corruption ray remaining? But how?`,TWN:`那麼侵蝕波還沒有消除？為什麼？`},stage:{bg:`CITY_STREET_DISASTER`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SPEAR_ALPHA_NULL_SHORT`,face:`UNIT_SURPRISE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`CHOWON_PERSONA_NULL_NULL`,text:{KOREA:`침식체가 원인이 아니라면 남은 가정은 하나죠.`,JPN:`侵食体が原因じゃないなら、残された仮定は一つです。`,ENG:`If C.O.s aren't the cause, there's only one other option.`,TWN:`如果原因不是侵蝕體，那就只剩下唯一一種可能。`},stage:{bg:`CITY_STREET_DISASTER`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CHOWON_PERSONA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`CHOWON_PERSONA_NULL_NULL`,text:{KOREA:`우리가 있는 이 현실이 침식되고 있는 걸지도요.`,JPN:`私たちのいるこの現実が侵食されているのかも。`,ENG:`Maybe Normalside is being Corrupted.`,TWN:`也許是我們身處的這個現實世界正在被侵蝕。`},stage:{bg:`CITY_STREET_DISASTER`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CHOWON_PERSONA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};